import path from "path"
import { tool } from "@opencode-ai/plugin"
import { $ } from "bun"

/**
 * Git commit tool with session tracking.
 *
 * Creates a git commit with:
 * - Automatic Session-ID trailer for tracking
 * - Session export file (aivocode/sessions/<id>/<id>.json) auto-staged
 * - Custom author (opencode/<agent>) for filtering commits
 * - Optional custom trailers (e.g., spec: feature-name)
 */
export default tool({
  description: `Create a git commit with session export and tracking.

Automatically includes:
- Session-ID trailer (always added)
- Session export file (aivocode/sessions/<id>/<id>.json) auto-staged
- Author: opencode/<agent> <noreply@opencode.ai>

Optional trailers:
- spec: Include when session reads/generates spec docs.
  Format: "spec: <feature-name>" (e.g., "spec: lsp-client")

Args:
- message: Commit description (what and why)
- files: Files to commit (required, session export auto-added)
- trailers: Additional custom trailers (optional)`,

  args: {
    message: tool.schema.string().describe("Commit message description"),
    files: tool.schema
      .array(tool.schema.string())
      .describe("Files to stage and commit (required)"),
    trailers: tool.schema
      .record(tool.schema.string(), tool.schema.string())
      .optional()
      .describe("Custom trailers (e.g., { spec: 'lsp-client' })"),
  },

  async execute(args, context) {
    const { sessionID, agent, worktree } = context
    const baseDir = worktree ?? process.cwd()

    // Validate required args
    if (!args.files || args.files.length === 0) {
      throw new Error("files array is required and cannot be empty")
    }

    // 1. Create session directory
    const sessionDir = path.join(baseDir, "aivocode/sessions", sessionID)
    await $`mkdir -p ${sessionDir}`

    // 2. Export session (inlined from export-session.ts)
    const exportPath = path.join(sessionDir, `${sessionID}.json`)
    const rawPath = `${exportPath}.raw.json`

    await $`sh -c ${`opencode export ${sessionID} > ${rawPath}`}`

    const rawJson = JSON.parse(await Bun.file(rawPath).text())
    const filtered = filterSession(rawJson)
    await Bun.write(exportPath, JSON.stringify(filtered, null, 2))
    await Bun.file(rawPath).unlink()

    // 3. Build trailer arguments (Session-ID always included)
    const trailerEntries: [string, string][] = [["Session-ID", sessionID]]
    if (args.trailers) {
      trailerEntries.push(...Object.entries(args.trailers))
    }
    const trailerArgs = trailerEntries
      .map(([k, v]) => `--trailer '${k}: ${v}'`)
      .join(" ")

    // 4. Build file list and stage all files (including session export)
    const allFiles = [...args.files, exportPath]
    const quotedFiles = allFiles.map((f) => `"${f}"`).join(" ")

    // 5. Execute git add and commit
    try {
      await $`sh -c ${`git add ${quotedFiles}`}`

      const commitCmd = `git commit --author="opencode/${agent} <noreply@opencode.ai>" --message "${args.message}" ${trailerArgs}`
      const result = await $`sh -c ${commitCmd}`.text()

      return `Committed successfully: ${result.trim()}\nSession-ID: ${sessionID}`
    } catch (error) {
      // Check if nothing to commit
      const statusResult = await $`git status --short`.text()
      if (!statusResult.trim()) {
        throw new Error("nothing to commit (working tree clean)")
      }
      throw error
    }
  },
})

// --- Inlined filtering logic (from export-session.ts) ---

type ToolInput = Record<string, unknown> | string | number | boolean | null

type FilteredMessage = {
  role?: string
  content?: string
  tools_used?: Array<{
    tool?: string
    input?: ToolInput
    output?: string
    status?: string
    sessionId?: string
  }>
}

const SKIP_OUTPUT_TOOLS = ["webfetch"]
const DEFAULT_OUTPUT_MAX_CHARS = 10000
const OUTPUT_MAX_CHARS: Record<string, number> = {
  bash: 1000,
  grep: 4000,
}

/**
 * Filter raw session export to extract relevant information.
 * Keeps: sessionID, message roles, text content, tool calls with truncated output.
 */
function filterSession(raw: unknown): { sessionID?: string; messages: FilteredMessage[] } {
  if (!raw || typeof raw !== "object") {
    return { messages: [] }
  }

  const rawRecord = raw as Record<string, unknown>
  const rawMessages = Array.isArray(rawRecord.messages)
    ? rawRecord.messages
    : Array.isArray(raw)
      ? raw
      : []

  const firstMessage = rawMessages.length > 0 ? rawMessages[0] : undefined
  const firstInfo =
    firstMessage && typeof firstMessage === "object"
      ? (firstMessage as Record<string, unknown>).info
      : undefined
  const firstSessionID =
    firstInfo && typeof firstInfo === "object"
      ? (firstInfo as Record<string, unknown>).sessionID
      : undefined

  const sessionID =
    (rawRecord.sessionID as string | undefined) ??
    (rawRecord.id as string | undefined) ??
    (typeof firstSessionID === "string" ? firstSessionID : undefined)

  const messages = rawMessages
    .map((message) => filterMessage(message))
    .filter((message) => message.content || (message.tools_used ?? []).length > 0)

  return { sessionID, messages }
}

/**
 * Extract role, text content, and tool calls from a message.
 */
function filterMessage(message: unknown): FilteredMessage {
  if (!message || typeof message !== "object") {
    return {}
  }

  const messageRecord = message as Record<string, unknown>
  const info = (messageRecord.info ?? {}) as Record<string, unknown>
  const role = info.role as string | undefined
  const parts = Array.isArray(messageRecord.parts) ? messageRecord.parts : []

  // Extract text parts
  const content = parts
    .filter((part) => {
      if (!part || typeof part !== "object") {
        return false
      }
      return (part as Record<string, unknown>).type === "text"
    })
    .map((part) => (part as Record<string, unknown>).text)
    .filter((text) => typeof text === "string")
    .join("\n")
    .trim()

  // Extract tool calls
  const tools_used = parts
    .filter((part) => isToolPart(part))
    .map((part) => normalizeToolPart(part))
    .filter((toolPart) => toolPart.tool || toolPart.input)

  return {
    role,
    content: content.length > 0 ? content : undefined,
    tools_used: tools_used.length > 0 ? tools_used : undefined,
  }
}

/**
 * Check if a message part is a tool call.
 */
function isToolPart(part: unknown): part is Record<string, unknown> {
  if (!part || typeof part !== "object") {
    return false
  }

  const partRecord = part as Record<string, unknown>
  return (
    partRecord.type === "tool" ||
    partRecord.type === "tool_call" ||
    partRecord.type === "tool-call"
  )
}

/**
 * Normalize a tool part to extract tool name, input, output, status.
 */
function normalizeToolPart(part: Record<string, unknown>): {
  tool?: string
  input?: ToolInput
  output?: string
  status?: string
  sessionId?: string
} {
  const tool = (part.tool ?? part.name) as string | undefined
  const state = (part.state ?? {}) as Record<string, unknown>
  const input = (state.input ?? part.input ?? part.args) as ToolInput

  // Truncate output for non-skipped tools
  let output: string | undefined
  if (tool && !SKIP_OUTPUT_TOOLS.includes(tool)) {
    const rawOutput = typeof state.output === "string" ? state.output : undefined
    if (rawOutput) {
      const maxChars = OUTPUT_MAX_CHARS[tool] ?? DEFAULT_OUTPUT_MAX_CHARS
      output =
        rawOutput.length > maxChars
          ? `${rawOutput.slice(0, maxChars)}... (truncated)`
          : rawOutput
    }
  }

  const status = typeof state.status === "string" ? state.status : undefined
  const metadata = (state.metadata ?? {}) as Record<string, unknown>
  const sessionId = typeof metadata.sessionId === "string" ? metadata.sessionId : undefined

  return { tool, input, output, status, sessionId }
}

